/*
  Analisa resultado do recovery e decide se precisa alertar.
  Se houver dead letters novos → alerta via WhatsApp.
*/
const result = $input.first().json;

// Parse response (Supabase RPC retorna o JSON diretamente)
const data = typeof result === 'string' ? JSON.parse(result) : result;

const resetCount     = data.reset_to_pending     || 0;
const deadLetterCount = data.moved_to_dead_letter || 0;
const deadIds         = data.dead_letter_ids      || [];

console.log(`[Recovery] Reset: ${resetCount} | Dead Letter: ${deadLetterCount}`);

// Decisão: precisa alertar?
const shouldAlert = deadLetterCount > 0;

// Buscar status geral da fila
let queueStatus = null;
try {
  const statusRes = await $helpers.httpRequest({
    method: 'GET',
    url:    `${$env.SUPABASE_URL}/rest/v1/vw_wa_queue_status`,
    headers: {
      'apikey':        $env.SUPABASE_SERVICE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_KEY}`,
    },
  });
  queueStatus = JSON.parse(statusRes.body);
} catch(e) {
  console.log('Queue status fetch failed:', e.message);
}

return [{
  json: {
    reset_to_pending:     resetCount,
    moved_to_dead_letter: deadLetterCount,
    dead_letter_ids:      deadIds,
    should_alert:         shouldAlert,
    queue_status:         queueStatus,
    ran_at:               new Date().toISOString(),
  }
}];
